    76→// LoadKBContext retrieves KB suggestions for a given error
    77→func (kb *KBIntegration) LoadKBContext(ctx context.Context, lang string, stdout, stderr []byte) (*KBContext, error) {
    78→	if !kb.config.Enabled {
    79→		return &KBContext{HasData: false}, nil
    80→	}
    81→
    82→	// Generate error signature
    83→	signature := kb.sigGen.GenerateSignature(lang, "unknown", stdout, stderr)
    84→
    85→	// Load recommended fixes
    86→	fixes, err := kb.summary.GetRecommendedFixes(ctx, lang, signature, 5)
    87→	if err != nil {
    88→		// KB read failure shouldn't break the workflow
    89→		return &KBContext{
    90→			Language:  lang,
    91→			Signature: signature,
    92→			HasData:   false,
    93→		}, nil
    94→	}
    95→
    96→	// Determine match confidence based on fix scores
    97→	var maxConfidence float64
    98→	for _, fix := range fixes {
    99→		if fix.Score > maxConfidence {
   100→			maxConfidence = fix.Score
   101→		}
   102→	}
   103→
   104→	return &KBContext{
   105→		Language:         lang,
   106→		Signature:        signature,
   107→		RecommendedFixes: fixes,
   108→		HasData:          len(fixes) > 0,
   109→		MatchConfidence:  maxConfidence,
   110→	}, nil
   111→}
