   113→// WriteHealingCase records a healing attempt in the KB
   114→func (kb *KBIntegration) WriteHealingCase(ctx context.Context, kbCtx *KBContext, attempt *HealingAttempt, outcome *HealingOutcome, stdout, stderr string) error {
   115→	if !kb.config.Enabled || !kb.config.WriteEnabled {
   116→		return nil
   117→	}
   118→
   119→	// Generate run ID (could be passed in from the runner)
   120→	runID := fmt.Sprintf("run-%d", time.Now().Unix())
   121→
   122→	// Create sanitized logs
   123→	sanitizedLogs := CreateSanitizedLogs(stdout, stderr)
   124→
   125→	// Create case context (would be populated with more data in real implementation)
   126→	caseContext := &CaseContext{
   127→		Language: kbCtx.Language,
   128→		// Additional context fields would be populated here
   129→	}
   130→
   131→	// Create case record
   132→	caseRecord := &CaseRecord{
   133→		RunID:     runID,
   134→		Timestamp: time.Now(),
   135→		Language:  kbCtx.Language,
   136→		Signature: kbCtx.Signature,
   137→		Context:   caseContext,
   138→		Attempt:   attempt,
   139→		Outcome:   outcome,
   140→		BuildLogs: sanitizedLogs,
   141→	}
   142→
   143→	// Store the case
   144→	err := kb.storage.WriteCase(ctx, kbCtx.Language, kbCtx.Signature, runID, caseRecord)
   145→	if err != nil {
   146→		// Log the error but don't fail the workflow
   147→		fmt.Printf("Warning: Failed to write KB case: %v\n", err)
   148→		return nil // Non-blocking
   149→	}
   150→
   151→	// Try to update summary (non-blocking)
   152→	go func() {
   153→		bgCtx := context.Background()
   154→		kb.summary.UpdateSummaryAfterCase(bgCtx, kbCtx.Language, kbCtx.Signature)
   155→	}()
   156→
   157→	return nil
   158→}
