   160→// ShouldUseKBSuggestions determines if KB suggestions should be used
   161→func (kb *KBIntegration) ShouldUseKBSuggestions(kbCtx *KBContext) bool {
   162→	if !kb.config.Enabled || !kbCtx.HasData {
   163→		return false
   164→	}
   165→
   166→	return kbCtx.MatchConfidence >= kb.config.ReadThreshold
   167→}
