   263→// DetectLanguageFromBuildError attempts to detect the programming language from build error
   264→func DetectLanguageFromBuildError(buildError string) string {
   265→	// Simple heuristic-based language detection
   266→	if containsAny(buildError, "javac", "Java", "java.lang", "org.java", "maven", "gradle") {
   267→		return "java"
   268→	}
   269→	if containsAny(buildError, "go build", "go.mod", "package main", "func main") {
   270→		return "go"
   271→	}
   272→	if containsAny(buildError, "tsc", "typescript", "node_modules", "npm", "yarn") {
   273→		return "typescript"
   274→	}
   275→	if containsAny(buildError, "python", "pip", "pytest", "import ") {
   276→		return "python"
   277→	}
   278→	if containsAny(buildError, "rustc", "cargo", "Cargo.toml") {
   279→		return "rust"
   280→	}
   281→
   282→	return "unknown" // Default fallback
   283→}
