   285→// containsAny checks if text contains any of the given substrings
   286→func containsAny(text string, substrings ...string) bool {
   287→	for _, substring := range substrings {
   288→		if len(substring) > 0 && len(text) >= len(substring) {
   289→			for i := 0; i <= len(text)-len(substring); i++ {
   290→				if text[i:i+len(substring)] == substring {
   291→					return true
   292→				}
   293→			}
   294→		}
   295→	}
   296→	return false
   297→}
