   419→func (kr *KBTransflowRunner) convertBranchResultToAttempt(result BranchResult) *HealingAttempt {
   420→	// This would extract the actual healing attempt from the branch result
   421→	// For now, return a basic structure
   422→	return &HealingAttempt{
